# -*- coding: utf-8 -*-
"""Skills management: sync skills from code to working_dir."""

import filecmp
import logging
import shutil
from pathlib import Path
from typing import Any
from pydantic import BaseModel
import frontmatter

from ..constant import ACTIVE_SKILLS_DIR, CUSTOMIZED_SKILLS_DIR

logger = logging.getLogger(__name__)


class SkillInfo(BaseModel):
    """Skill information structure.

    The references and scripts fields represent directory trees
    as nested dicts.

    When reading existing skills:
    - Files are represented as {filename: None}
    - Directories are represented as {dirname: {nested_structure}}

    When creating new skills via SkillService.create_skill:
    - Files are represented as {filename: "content"}
    - Directories are represented as {dirname: {nested_structure}}

    Example (reading):
        {
            "file.txt": None,
            "subdir": {
                "nested.py": None,
                "deeper": {
                    "file.sh": None
                }
            }
        }
    """

    name: str
    description: str = ""
    content: str
    source: str  # "builtin", "customized", or "active"
    path: str
    references: dict[str, Any] = {}
    scripts: dict[str, Any] = {}


def get_builtin_skills_dir() -> Path:
    """Get the path to built-in skills directory in the code."""
    return Path(__file__).parent / "skills"


def get_customized_skills_dir() -> Path:
    """Get the path to customized skills directory in working_dir."""
    return CUSTOMIZED_SKILLS_DIR


def get_active_skills_dir() -> Path:
    """Get the path to active skills directory in working_dir."""
    return ACTIVE_SKILLS_DIR


def get_working_skills_dir() -> Path:
    """
    Get the path to skills directory in working_dir.

    Deprecated: Use get_active_skills_dir() instead.
    """
    return get_active_skills_dir()


def _build_directory_tree(directory: Path) -> dict[str, Any]:
    """
    Recursively build a directory tree structure.

    Args:
        directory: Directory to scan.

    Returns:
        Dictionary representing the tree structure where:
        - Files are represented as {filename: None}
        - Directories are represented as {dirname: {nested_structure}}

    Example:
        {
            "file1.txt": None,
            "subdir": {
                "file2.py": None,
                "nested": {
                    "file3.sh": None
                }
            }
        }
    """
    tree: dict[str, Any] = {}

    if not directory.exists() or not directory.is_dir():
        return tree

    for item in sorted(directory.iterdir()):
        if item.is_file():
            tree[item.name] = None
        elif item.is_dir():
            tree[item.name] = _build_directory_tree(item)

    return tree


def _collect_skills_from_dir(directory: Path) -> dict[str, Path]:
    """
    Collect skills from a directory.

    Args:
        directory: Directory to scan for skills.

    Returns:
        Dictionary mapping skill names to their paths.
    """
    skills: dict[str, Path] = {}
    if directory.exists():
        for skill_dir in directory.iterdir():
            if skill_dir.is_dir() and (skill_dir / "SKILL.md").exists():
                skills[skill_dir.name] = skill_dir
    return skills


def sync_skills_to_working_dir(
    skill_names: list[str] | None = None,
    force: bool = False,
) -> tuple[int, int]:
    """
    Sync skills from builtin and customized to active_skills directory.

    Args:
        skill_names: List of skill names to sync. If None, sync all skills.
        force: If True, overwrite existing skills in active_skills.

    Returns:
        Tuple of (synced_count, skipped_count).
    """
    builtin_skills = get_builtin_skills_dir()
    customized_skills = get_customized_skills_dir()
    active_skills = get_active_skills_dir()

    # Ensure active skills directory exists
    active_skills.mkdir(parents=True, exist_ok=True)

# -*- coding: utf-8 -*-
"""CLI commands for managing LLM providers."""
from __future__ import annotations

import asyncio
from typing import Optional

import click

from ..providers.ollama_manager import OllamaModelManager
from ..providers.provider import ModelInfo, Provider, ProviderInfo
from ..providers.provider_manager import ProviderManager
from .utils import prompt_choice


def _manager() -> ProviderManager:
    return ProviderManager.get_instance()


def _mask_api_key(api_key: str) -> str:
    if not api_key:
        return ""
    if len(api_key) <= 8:
        return "*" * len(api_key)
    return f"{api_key[:4]}...{api_key[-2:]}"


def _is_configured(provider: Provider) -> bool:
    if provider.is_local or provider.id == "ollama":
        return True
    # for API-based providers, we consider them
    # configured if they have a base URL and (if required) an API key
    if not provider.base_url:
        return False
    if provider.require_api_key and not provider.api_key:
        return False
    return True


def _save_provider(manager: ProviderManager, provider_id: str) -> None:
    provider = manager.get_provider(provider_id)
    if provider is None:
        return
    manager._save_provider(  # pylint: disable=protected-access
        provider,
        is_builtin=provider_id in manager.builtin_providers,
    )


def _all_provider_objects(manager: ProviderManager) -> list[Provider]:
    objs: list[Provider] = []
    for info in asyncio.run(manager.list_provider_info()):
        provider = manager.get_provider(info.id)
        if provider is not None:
            objs.append(provider)
    return objs


def _get_ollama_host() -> str:
    manager = _manager()
    provider = manager.get_provider("ollama")
    if provider is None or not provider.base_url:
        return "http://localhost:11434"
    return provider.base_url


def _select_provider_interactive(
    prompt_text: str = "Select provider:",
    *,
    default_pid: str = "",
) -> str:
    """Prompt user to pick a provider. Returns provider_id."""
    manager = _manager()
    all_providers = _all_provider_objects(manager)

    labels: list[str] = []
    ids: list[str] = []
    for provider in all_providers:
        mark = "✓" if _is_configured(provider) else "✗"
        labels.append(f"{provider.name} ({provider.id}) [{mark}]")
        ids.append(provider.id)

    default_label: Optional[str] = None
    if default_pid in ids:
        default_label = labels[ids.index(default_pid)]

    chosen_label = prompt_choice(
        prompt_text,
        options=labels,
        default=default_label,
    )
    return ids[labels.index(chosen_label)]


def configure_provider_api_key_interactive(
    provider_id: str | None = None,
) -> str:
    """Interactively configure a provider's API key. Returns provider_id."""
    manager = _manager()

    if provider_id is None:
        provider_id = _select_provider_interactive(
            "Select provider to configure API key:",
        )

    defn = manager.get_provider(provider_id)
    if defn is None:
        click.echo(
            click.style(
                f"Error: provider '{provider_id}' not found.",
                fg="red",
            ),
        )
        raise SystemExit(1)
    if not defn.require_api_key:
        click.echo(
            f"{defn.name} does not require API key configuration. Skipping.",
        )
        return provider_id

    current_base, current_key = defn.base_url, defn.api_key

    base_url: Optional[str] = None
    # Prompt for base_url if the provider is custom or has no default URL
    # (e.g. Azure OpenAI requires user to provide their endpoint).
    if defn.is_custom or provider_id == "azure-openai" or not current_base:
        azure_hint = (
            "Azure endpoint "
            "(e.g. https://<resource>.openai.azure.com/openai/v1)"
        )
        url_hint = (
            azure_hint
            if provider_id == "azure-openai"
            else "Base URL (OpenAI-compatible endpoint)"
        )
        base_url = click.prompt(
            url_hint,
            default=current_base or "",
            show_default=bool(current_base),
        ).strip()
        if not base_url:
            click.echo(click.style("Error: base_url is required.", fg="red"))
            raise SystemExit(1)

    hint = (
        f"prefix: {defn.api_key_prefix}" if defn.api_key_prefix else "optional"
    )
    api_key = click.prompt(
        f"API key ({hint})",
        default=current_key or "",

