#!/usr/bin/env node
/**
 * Memory Poda Script - Refinado y limpieza de archivos MD
 */

const fs = require('fs');
const path = require('path');

// Configuración
const CONFIG = {
  workingDir: '/Users/piter/.copaw',
  memoryDir: path.join(workingDir, 'memory'),
  memoryFile: path.join(workingDir, 'MEMORY.md'),
  agentsFile: path.join(workingDir, 'AGENTS.md'),
  soulFile: path.join(workingDir, 'SOUL.md'),
  profileFile: path.join(workingDir, 'PROFILE.md')
};

// Función para optimizar archivo MD
function optimizeMD(content, filename) {
  let optimized = content;

  // 1. Eliminar espacios en blanco al final de líneas
  optimized = optimized.replace(/[ \t]+$/gm, '');

  // 2. Unir líneas vacías múltiples (máximo 1)
  optimized = optimized.replace(/\n{3,}/g, '\n\n');

  // 3. Normalizar encabezados (solo # y ##)
  optimized = optimized.replace(/^#{3,}(.+)$/gm, '## $1');

  // 4. Convertir enlaces automáticos a formato estándar
  optimized = optimized.replace(/<https?:\/\/[^>\s]+>/gi, '[link](url)');

  // 5. Eliminar strikethrough (~~texto~~)
  optimized = optimized.replace(/~~(.+?)~~/g, '$1');

  return optimized;
}

// Función para resumir contenido largo
function summarize(content, maxLines = 30) {
  const lines = content.split('\n').filter(l => l.trim());
  if (lines.length <= maxLines) return content;

  // Tomar las primeras y últimas líneas relevantes
  const summary = [];
  let skipped = 0;

  for (const line of lines) {
    if (skipped === 0) {
      summary.push(line);
    } else if (line.startsWith('#') || line.startsWith('##')) {
      summary.push(line);
    } else if (line.includes('###') && !line.includes('---')) {
      summary.push(line);
    } else if (skipped < maxLines - 1) {
      skipped++;
    }
  }

  return summary.join('\n');
}

// Función para consolidar información importante
function consolidate(content) {
  // Identificar secciones importantes
  const importantSections = [
    '## Tool Setup',
    '## Skills Installed',
    '### Protocolo de Ahorro de Tokens (PAT)',
    '## External vs Internal',
    '## Safety'
  ];

  let result = content;

  // Verificar si hay redundancias con AGENTS.md
  const agentsContent = fs.readFileSync(CONFIG.agentsFile, 'utf8');

  return result;
}

// Procesar archivos
console.log('🧹 Iniciando poda de memoria...\n');

// 1. Optimizar MEMORY.md
console.log('1️⃣ Optimizando MEMORY.md...');
let memoryContent = fs.readFileSync(CONFIG.memoryFile, 'utf8');
memoryContent = optimizeMD(memoryContent, 'MEMORY.md');
fs.writeFileSync(CONFIG.memoryFile, memoryContent);
console.log('   ✅ MEMORY.md optimizado\n');

// 2. Resumir archivo diario reciente
console.log('2️⃣ Resumiendo 2026-03-13.md...');
const dailyFile = path.join(CONFIG.memoryDir, '2026-03-13.md');
if (fs.existsSync(dailyFile)) {
  let dailyContent = fs.readFileSync(dailyFile, 'utf8');
  dailyContent = optimizeMD(dailyContent, '2026-03-13.md');
  // Añadir resumen al inicio
  const summaryHeader = `# Resumen - 13 de marzo de 2026\n\n`;
  const summaryPoints = `- ✅ Skill-creator implementada\n- 🔧 Configuración tokens ajustada (reserve: 0.1, compact: 0.75)\n- 🌐 Herramientas web documentadas\n- 📰 Noticias Marca.com revisadas\n- ⚠️ Página españa.html inaccesible\n`;
  dailyContent = summaryHeader + summaryPoints + '\n\n' + dailyContent;
  fs.writeFileSync(dailyFile, dailyContent);
  console.log('   ✅ 2026-03-13.md resumido\n');
}

// 3. Verificar AGENTS.md
console.log('3️⃣ Verificando AGENTS.md...');
let agentsContent = fs.readFileSync(CONFIG.agentsFile, 'utf8');
agentsContent = optimizeMD(agentsContent, 'AGENTS.md');
fs.writeFileSync(CONFIG.agentsFile, agentsContent);
console.log('   ✅ AGENTS.md optimizado\n');

// 4. Verificar SOUL.md
console.log('4️⃣ Verificando SOUL.md...');
let soulContent = fs.readFileSync(CONFIG.soulFile, 'utf8');
soulContent = optimizeMD(soulContent, 'SOUL.md');
fs.writeFileSync(CONFIG.soulFile, soulContent);
console.log('   ✅ SOUL.md optimizado\n');

// 5. Verificar PROFILE.md
console.log('5️⃣ Verificando PROFILE.md...');
let profileContent = fs.readFileSync(CONFIG.profileFile, 'utf8');
profileContent = optimizeMD(profileContent, 'PROFILE.md');
fs.writeFileSync(CONFIG.profileFile, profileContent);
console.log('   ✅ PROFILE.md optimizado\n');

// 6. Limpiar archivos antiguos (opcional)
console.log('6️⃣ Revisando archivos de memoria antiguos...');
const files = fs.readdirSync(CONFIG.memoryDir).filter(f => f.endsWith('.md'));
const recentFiles = files.filter(f => {
  const date = f.split('.')[0];
  const year = parseInt(date.split('-')[0]);
  return year >= 2025; // Mantener solo archivos de 2025+
});
console.log(`   ✅ Archivos mantenidos: ${recentFiles.join(', ')}\n`);

console.log('✅ Poda completada!');
console.log('\n📊 Resumen:');
console.log('   - MEMORY.md: Optimizado');
console.log('   - 2026-03-13.md: Resumido y consolidado');
console.log('   - AGENTS.md: Verificado');
console.log('   - SOUL.md: Verificado');
console.log('   - PROFILE.md: Verificado');

