function optimizeMD(content, filename) {
  let optimized = content;

  // 1. Eliminar espacios en blanco al final de líneas
  optimized = optimized.replace(/[ \t]+$/gm, '');

  // 2. Unir líneas vacías múltiples (máximo 1)
  optimized = optimized.replace(/\n{3,}/g, '\n\n');

  // 3. Normalizar encabezados (solo # y ##)
  optimized = optimized.replace(/^#{3,}(.+)$/gm, '## $1');

  // 4. Convertir enlaces automáticos a formato estándar
  optimized = optimized.replace(/<https?:\/\/[^>\s]+>/gi, '[link](url)');

  // 5. Eliminar strikethrough (~~texto~~)
  optimized = optimized.replace(/~~(.+?)~~/g, '$1');

  return optimized;
